// Due for a nudge: opener sent 5+ days ago, no reply yet, never nudged before.
const NUDGE_AFTER_DAYS = 5;
const MAX = 10;
const cutoff = Date.now() - NUDGE_AFTER_DAYS * 86400 * 1000;
const rows = $input.all().map(function (i) { return i.json; });
const due = rows.filter(function (r) {
  const status = String(r.status || '').trim().toLowerCase();
  const nextAction = String(r.next_action || '').trim().toLowerCase();
  if (status !== 'opener_sent') return false;
  if (nextAction === 'nudged') return false;
  const lt = Date.parse(r.last_touch || '');
  if (isNaN(lt)) return false;
  return lt < cutoff;
});
return due.slice(0, MAX).map(function (r) { return { json: r }; });

// Fetch Layer 1 brain once, build a nudge-draft request per prospect.
const repo = 'https://raw.githubusercontent.com/isaiahwong-bit/Digital-Artifacts';
const refs = ['main', 'feat/sales-ops-automation'];
const files = ['outbound-offer', 'tone-of-voice', 'company-brief'];
const brain = {};
for (const f of files) {
  let got = null;
  for (const ref of refs) {
    try {
      got = await this.helpers.httpRequest({ method: 'GET', url: repo + '/' + ref + '/brain/' + f + '.md', encoding: 'text', json: false });
      break;
    } catch (e) { got = null; }
  }
  if (got === null) throw new Error('Brain file unreachable on any branch: ' + f);
  brain[f] = got;
}

const nudgeSystem = 'You write a brief follow-up nudge email from Isaiah at Digital Artifacts to a prospect who received a cold opener several days ago and has not replied. HARD RULES: no em dashes ever, use a comma or period instead. One short paragraph, warm and genuinely low pressure, never pushy. Lightly acknowledge you reached out before, do not repeat the original email. Re-state the single ask: reply with the one task eating the most time and you will send back a free one-page teardown. Under 60 words in body_plain excluding the footer. Sign off Isaiah only. End body_plain with the token {{ SENDER_FOOTER }} on its own final line. Return JSON only, no prose, no markdown fences.';
const schema = '{"subject":"short, can follow on from the original","body_plain":"the nudge as plain text, ends with {{ SENDER_FOOTER }} on its own final line","confidence":"high|medium|low","notes_for_isaiah":"one sentence"}';

const items = $input.all();
return items.map(function (it, idx) {
  const p = it.json;
  const firstName = String(p.contact_name || '').split(' ')[0] || 'there';
  const content = '<offer>\n' + brain['outbound-offer'] + '\n</offer>\n\n'
    + '<tone>\n' + brain['tone-of-voice'] + '\n</tone>\n\n'
    + '<company>\n' + brain['company-brief'] + '\n</company>\n\n'
    + '<prospect>\nBusiness: ' + (p.business_name || '') + '\nContact first name: ' + firstName + '\nLikely pain: ' + (p.likely_pain || '') + '\n</prospect>\n\n'
    + '<original_opener>\n' + (p.opener_body || '') + '\n</original_opener>\n\n'
    + 'Write the follow-up nudge. Return strictly this JSON, nothing else:\n' + schema;
  const nudge_request = { model: 'claude-sonnet-4-6', max_tokens: 500, system: nudgeSystem, messages: [{ role: 'user', content: content }] };
  return { json: { ...p, nudge_request: nudge_request }, pairedItem: { item: idx } };
});

// Parse the nudge, inject the compliance footer, build the sheet row + Telegram brief.
const prev = $('Prep Brain + Nudge Bodies').item.json;
const raw = ($json && $json.content && $json.content[0] && $json.content[0].text) || '';
let n;
try { const s = raw.indexOf('{'); const e = raw.lastIndexOf('}'); n = JSON.parse(raw.slice(s, e + 1)); }
catch (err) { n = { subject: '', body_plain: '', confidence: 'low', notes_for_isaiah: 'Nudge response could not be parsed. Do not approve, regenerate this one.' }; }

const unsubUrl = 'https://n8nbeginner-sga.app.n8n.cloud/webhook/da-unsubscribe?id=' + encodeURIComponent(prev.prospect_id || '') + '&list=outbound';
const footer = ',\n,\nDigital Artifacts, Sydney NSW, Australia. Sent by Isaiah Wong, isaiah@digitalartifacts.com.au\n'
  + 'Not interested? Reply with the word unsubscribe, or use this link: ' + unsubUrl + '. You will be removed straight away.';
let body = String(n.body_plain || '');
if (body.indexOf('{{ SENDER_FOOTER }}') !== -1) body = body.split('{{ SENDER_FOOTER }}').join(footer);
else if (body.indexOf('{{SENDER_FOOTER}}') !== -1) body = body.split('{{SENDER_FOOTER}}').join(footer);
else body = body.replace(/\s*$/, '') + '\n' + footer;
body = body.replace(/—|–/g, ',');

const subject = n.subject || ('Following up - ' + (prev.business_name || ''));
const now = new Date().toISOString();
const tg_text = ('FOLLOW-UP NUDGE for approval - ' + (prev.business_name || '') + '\n\n'
  + 'To: ' + (prev.contact_name || 'no name') + ' (' + (prev.email || '') + ')\n\n'
  + 'Subject: ' + subject + '\n\n'
  + body + '\n\n-------\n'
  + (n.notes_for_isaiah || 'No notes.')).slice(0, 3900);

return { json: {
  prospect_id: prev.prospect_id || '',
  business_name: prev.business_name || '',
  contact_name: prev.contact_name || '',
  email: prev.email || '',
  nudge_subject: subject,
  nudge_body: body,
  now: now,
  tg_text: tg_text,
} };
